/**
 * Memoized cell components for TaskList datagrid
 * These prevent unnecessary re-renders when other rows update
 */

const TaskTitleCell = React.memo(function TaskTitleCell({ record }: { record: Task }) {
  return (
    <div className="flex items-center gap-2">
      <TruncatedText className="max-w-[200px]">{record.title}</TruncatedText>
      <SnoozeBadge snoozeUntil={record.snooze_until} />
    </div>
  );
});

const TaskPriorityCell = React.memo(function TaskPriorityCell({ record }: { record: Task }) {
  if (!record.priority) return null;
  return (
    <FilterableBadge source="priority" value={record.priority}>
      <PriorityBadge priority={record.priority} />
    </FilterableBadge>
  );
});

const TaskTypeCell = React.memo(function TaskTypeCell({ record }: { record: Task }) {
  if (!record.type) return null;
  return (
    <FilterableBadge source="type" value={record.type}>
      <Badge variant="outline">{record.type}</Badge>
    </FilterableBadge>
  );
});

const TaskContactNameCell = React.memo(function TaskContactNameCell({
  record,
}: {
  record: { first_name?: string; last_name?: string };
}) {
  return <>{[record?.first_name, record?.last_name].filter(Boolean).join(" ") || "—"}</>;
});

interface TaskActionsCellProps {
  record: Task;
  openSlideOver: (id: number, mode: "view" | "edit") => void;
}

const TaskActionsCell = React.memo(function TaskActionsCell({
  record,
  openSlideOver,
}: TaskActionsCellProps) {
  return (
    <RowHoverActions
      className="inline-flex items-center justify-end gap-1"
      recordId={record.id}
      resource="tasks"
      onView={(id) => openSlideOver(Number(id), "view")}
      onEdit={(id) => openSlideOver(Number(id), "edit")}
    />
  );
});

/**
 * TaskList - Standard list page for Task records
 *
 * Uses ListPageLayout for centralized empty-state branching,
 * loading states, filter cleanup, and bulk actions.
 *
 * Features:
 * - Identity-aware rendering with skeleton loading
 * - Keyboard navigation with slide-over integration
 * - BulkActionsToolbar for selection operations
 * - Responsive columns using COLUMN_VISIBILITY semantic presets
 * - Inline completion checkbox (prevents row click propagation)
 * - Edit mode by default in slide-over (tasks are action items)
 */
export default function TaskList() {
  const { data: identity, isPending: isIdentityPending } = useGetIdentity();
  const { slideOverId, isOpen, mode, openSlideOver, closeSlideOver, toggleMode } =
    useSlideOverState();

  if (isIdentityPending) {
    return <TaskListSkeleton />;
  }
  if (!identity) {
    return null;
  }

  return (
    <>
      <div>
        <List
          title={false}
          actions={false}
          perPage={100}
          sort={{ field: "due_date", order: "ASC" }}
          exporter={exporter}
          pagination={<ListPagination rowsPerPageOptions={[25, 50, 100]} />}
        >
          <ListPageLayout
            resource="tasks"
            filterComponent={<TaskListFilter />}
            filterConfig={TASK_FILTER_CONFIG}
            sortFields={["title", "due_date", "priority", "type"]}
            searchPlaceholder="Search tasks..."
            overflowActions={<ExportMenuItem />}
            primaryAction={<CreateButton variant="default" />}
            emptyState={<TaskEmpty />}
            loadingSkeleton={<TaskListSkeleton />}
            bulkActions={<BulkActionsToolbarChildren />}
          >
            <TaskDatagrid openSlideOver={openSlideOver} isSlideOverOpen={isOpen} />
          </ListPageLayout>
        </List>
      </div>

      <TaskSlideOver
        recordId={slideOverId}
        isOpen={isOpen}
        mode={mode}
        onClose={closeSlideOver}
        onModeToggle={toggleMode}
      />
    </>
  );
}

/**
 * TaskDatagrid - Keyboard-navigable datagrid with slide-over integration
 *
 * Contains useUpdate/useNotify/useQueryClient hooks for the inline
 * completion checkbox functionality.
 */
const TaskDatagrid = ({
  openSlideOver,
  isSlideOverOpen,
}: {
  openSlideOver: (id: number, mode: "view" | "edit") => void;
  isSlideOverOpen: boolean;
}) => {
  const [update] = useUpdate();
  const notify = useNotify();
  const queryClient = useQueryClient();

  // Handler for when user clicks completion checkbox - direct completion without dialog
  const handleCompletionRequest = async (task: Task, checked: boolean) => {
    try {
      if (checked) {
        // Complete task directly
        await update(
          "tasks",
          {
            id: task.id,
            data: { completed: true, completed_at: new Date().toISOString() },
            previousData: task,
          },
          { returnPromise: true }
        );
        notify("Task completed", { type: "success" });
      } else {
        // Reopen task
        await update(
          "tasks",
          {
            id: task.id,
            data: { completed: false, completed_at: null },
            previousData: task,
          },
          { returnPromise: true }
        );
        notify("Task reopened", { type: "success" });
      }
      queryClient.invalidateQueries({ queryKey: taskKeys.lists() });
      queryClient.invalidateQueries({ queryKey: entityTimelineKeys.lists() });
    } catch {
      notify(checked ? "Failed to complete task" : "Failed to reopen task", {
        type: "error",
      });
    }
  };

  const { focusedIndex } = useListKeyboardNavigation({
    onSelect: (id) => openSlideOver(Number(id), "view"),
    enabled: !isSlideOverOpen,
  });

  return (
    <PremiumDatagrid
      onRowClick={(id) => openSlideOver(Number(id), "view")}
      focusedIndex={focusedIndex}
    >
      {/* Column 1: Completion - Inline checkbox (non-sortable) - always visible */}
      <FunctionField
        label="Done"
        sortable={false}
        render={(record: Task) => (
          <CompletionCheckbox task={record} onCompletionRequest={handleCompletionRequest} />
        )}
        {...COLUMN_VISIBILITY.always}
      />

      {/* Column 2: Title - Primary identifier (sortable) - always visible */}
      <FunctionField
        label={<TaskTitleHeader />}
        sortBy="title"
        render={(record: Task) => <TaskTitleCell record={record} />}
        {...COLUMN_VISIBILITY.always}
      />

      {/* Column 3: Due Date - Time-sensitive field (sortable) - always visible */}
      <DateField source="due_date" label="Due Date" sortable {...COLUMN_VISIBILITY.always} />

      {/* Column 4: Priority - Visual indicator (sortable) - always visible */}
      <FunctionField
        label={<TaskPriorityHeader />}
        sortBy="priority"
        render={(record: Task) => <TaskPriorityCell record={record} />}
        {...COLUMN_VISIBILITY.always}
      />

      {/* Column 5: Type - Classification badge (sortable) - hidden on tablet/mobile */}
      <FunctionField
        label={<TaskTypeHeader />}
        sortBy="type"
        render={(record: Task) => <TaskTypeCell record={record} />}
        {...COLUMN_VISIBILITY.ipadPlus}
      />

      {/* Column 6: Assigned To - Sales reference (sortable) - hidden on tablet/mobile */}
      <ReferenceField
        source="sales_id"
        reference="sales"
        label="Assigned To"
        link={false}
        sortable
        {...COLUMN_VISIBILITY.ipadPlus}
      >
        <SaleName />
      </ReferenceField>

      {/* Column 7: Contact - Contact reference (non-sortable) - hidden until large desktop */}
      <ReferenceField
        source="contact_id"
        reference="contacts_summary"
        label="Contact"
        link="show"
        sortable={false}
        {...COLUMN_VISIBILITY.desktopPlus}
      >
        <FunctionField
          render={(record: { first_name?: string; last_name?: string }) => (
            <TaskContactNameCell record={record} />
          )}
        />
      </ReferenceField>

      {/* Column 8: Opportunity - Opportunity reference (non-sortable) - hidden until large desktop */}
      <ReferenceField
        source="opportunity_id"
        reference="opportunities"
        label="Opportunity"
        link="show"
        sortable={false}
        {...COLUMN_VISIBILITY.desktopPlus}
      >
        <TextField source="name" />
      </ReferenceField>

      {/* Column 9: Actions - Row action menu (non-sortable) - always visible */}
      <FunctionField
        label="Actions"
        sortable={false}
        cellClassName="w-[72px] sm:w-[88px] text-right"
        render={(record: Task) => <TaskActionsCell record={record} openSlideOver={openSlideOver} />}
        {...COLUMN_VISIBILITY.always}
      />
    </PremiumDatagrid>
  );
};

/**
 * CompletionCheckbox - Inline task completion toggle
 *
 * CRITICAL: Prevents row click propagation to allow independent checkbox interaction.
 * Memoized to prevent re-renders when other rows update.
 */
const CompletionCheckbox = React.memo(function CompletionCheckbox({
  task,
  onCompletionRequest,
}: {
  task: Task;
  onCompletionRequest: (task: Task, checked: boolean) => void;
}) {
  const handleToggle = (e: React.ChangeEvent<HTMLInputElement>) => {
    // Prevent row click
    e.stopPropagation();
    onCompletionRequest(task, e.target.checked);
  };

  return (
    <label className="flex items-center justify-center h-11 w-11 cursor-pointer">
      <input
        type="checkbox"
        checked={task.completed || false}
        onChange={handleToggle}
        onClick={(e) => e.stopPropagation()}
        className="h-4 w-4 rounded border-input focus:ring-2 focus:ring-primary focus:ring-offset-2"
        aria-label={
          task.completed ? `Mark "${task.title}" as incomplete` : `Mark "${task.title}" as complete`
        }
      />
    </label>
  );
});

/**
 * CSV exporter for Task records
 */
const exporter: Exporter<Task> = async (records, fetchRelatedRecords) => {
  const opportunities = await fetchRelatedRecords<Opportunity>(
    records,
    "opportunity_id",
    "opportunities"
  );

  const organizationIds = Array.from(
    new Set(
      opportunities.flatMap((opp) => (opp.organization_id ? [opp.organization_id as number] : []))
    )
  );

  const organizations =
    organizationIds.length > 0
      ? await fetchRelatedRecords<Organization>(
          organizationIds.map((id) => ({ id, organization_id: id })),
          "organization_id",
          "organizations"
        )
      : [];

  const oppMap = new Map(opportunities.map((opp) => [opp.id, opp]));
  const orgMap = new Map(organizations.map((org) => [org.id, org]));

  const dataForExport = records.map((task) => {
    const opp = task.opportunity_id ? oppMap.get(task.opportunity_id as number) : null;
    const org = opp?.organization_id ? orgMap.get(opp.organization_id as number) : null;

    return {
      id: task.id,
      title: task.title,
      description: task.description,
      type: task.type,
      priority: task.priority,
      due_date: task.due_date,
      completed: task.completed ? "Yes" : "No",
      completed_at: task.completed_at || "",
      principal: org?.name || "",
      opportunity_id: task.opportunity_id || "",
      contact_id: task.contact_id || "",
      created_at: task.created_at,
    };
  });

  jsonExport(
    dataForExport,
    {
      headers: [
        "id",
        "title",
        "description",
        "type",
        "priority",
        "due_date",
        "completed",
        "completed_at",
        "principal",
        "opportunity_id",
        "contact_id",
        "created_at",
      ],
    },
    (err, csv) => {
      if (err) {
        throw new Error(`CSV export failed: ${err.message}`);
      }
      downloadCSV(csv, "tasks");
    }
  );
};
